    'Türk Dili ve Edebiyatı': ["1. Tema: Sözün İnceliği (Giriş ve Hikaye) - Edebiyatın bilim/sanatla ilişkisi, olay/durum hikayesi, yapı unsurları.", "2. Tema: Anlam Arayışı (Şiir) - Nazım birimi, kafiye, redif, ölçü, söz sanatları.", "3. Tema: Anlamın Yapı Taşları (Masal, Fabl ve Roman) - Özellikleri, bölümleri, romanın yapı unsurları.", "4. Tema: Dilin Zenginliği (Tiyatro, Anı, Biyografi) - Modern/geleneksel tiyatro, biyografi, dil bilgisi kuralları."],
    'Kimya': ["1. Ünite: Kimya Bilimi - Simyadan kimyaya, kimya disiplinleri.", "2. Ünite: Atom ve Periyodik Sistem - Atom modelleri, periyodik özellikler.", "3. Ünite: Kimyasal Türler Arası Etkileşimler - İyonik, kovalent ve metalik bağlar.", "4. Ünite: Maddenin Halleri - Katı, sıvı, gaz ve plazma.", "5. Ünite: Doğa ve Kimya"],
    'Biyoloji': ["1. Tema: Yaşam - Biyolojinin önemi, canlıların ortak özellikleri, temel bileşenleri ve hücre.", "2. Tema: Organizasyon - Hücre yapısı, madde geçişleri, canlıların sınıflandırılması ve biyoçeşitlilik."],
    'Fizik': ["1. Ünite: Fizik Bilimi ve Kariyer Keşfi - Fiziğin doğası, alt dalları ve fiziksel nicelikler.", "2. Ünite: Kuvvet ve Hareket - Hareket kavramları, Newton'un Hareket Yasaları ve temel kuvvetler.", "3. Ünite: Akışkanlar - Basınç, kaldırma kuvveti, Bernoulli İlkesi, adezyon ve kohezyon.", "4. Ünite: Enerji - İş, güç, enerji kavramları ve enerji dönüşümleri."],
    'Tarih': ["1. Ünite: Geçmişin İnşa Sürecinde Tarih - Tarihin doğası, tarihsel bilgi üretimi, araştırma ve dijitalleşme.", "2. Ünite: Eski Çağ Medeniyetleri - İnsanlığın ilk dönemleri, yazının icadı, göçler, devletler ve hukuk sistemleri.", "3. Ünite: Orta Çağ Medeniyetleri - Orta Çağ'da siyasi yapılar, tarım, ticaret, hukuk sistemi ve kültür merkezleri."],
    'Coğrafya': ["1. Ünite: Coğrafyanın Doğası - Coğrafyanın konusu, önemi ve gelişimi.", "2. Ünite: Mekânsal Bilgi Teknolojileri - Harita okuryazarlığı ve konum özellikleri.", "3. Ünite: Doğal Sistemler ve Süreçler - İklim, dünyanın şekli ve hareketleri.", "4. Ünite: Beşeri Sistemler ve Süreçler - Nüfus, göç hareketleri ve yerleşme.", "5. Ünite: Ekonomik Faaliyetler ve Etkileri - Ekonomik faaliyet türleri ve doğal kaynaklar."],
    'Felsefe': ["1. Ünite: Felsefenin Doğası - Felsefi düşüncenin özellikleri, soru örnekleri ve bilim/din/sanat ilişkisi.", "2. Ünite: Felsefe, Mantık ve Argümantasyon - Düşünme-dil ilişkisi, mantık kavramları (önerme, argüman) ve argümantasyon yapısı.", "3. Ünite: Varlık Felsefesi (Ontoloji) - Varlık felsefesinin konusu, temel kavramları ve problemleri.", "4. Ünite: Bilgi Felsefesi (Epistemoloji) - Bilgi felsefesinin temel kavramları, bilginin kaynağı ve değeri."],
    'Din Kültürü ve Ahlak Bilgisi': ["1. Ünite: Allah-İnsan İlişkisi - İnsanın yaratılışı, evrendeki konumu, bilgiye ulaşma yolları ve dua.", "2. Ünite: İslam'da İnanç Esasları - İmanın mahiyeti, İslam'ın inanç esasları ve ayet/hadislerle analizi.", "3. Ünite: İslam'da İbadetler - İbadetin anlamı/amacı ve temel ibadetlerin (namaz, oruç vb.) hikmetleri.", "4. Ünite: İslam'da Ahlak İlkeleri - İslam ahlakının özellikleri, Kur'an ve sünnetteki ahlaki tutumlar.", "5. Ünite: Kur'an'a Göre Hz. Muhammed (s.a.v.) - Hz. Muhammed'in peygamberliği, örnekliği ve ehlibeyt sevgisi."],
    'İngilizce': ["Unit 1: Studying Abroad (Yurtdışında Eğitim)", "Unit 2: My Environment (Çevrem)", "Unit 3: Movies (Filmler)", "Unit 4: Human In Nature (Doğada İnsan)", "Unit 5: Inspirational People (İlham Veren İnsanlar)", "Unit 6: Bridging Cultures (Kültürleri Köprülemek)", "Unit 7: World Heritage (Dünya Mirası)", "Unit 8: Emergency and Health Problems (Acil Durum ve Sağlık Sorunları)", "Unit 9: Invitations and Celebrations (Davetler ve Kutlamalar)", "Unit 10: Television and Social Media (Televizyon ve Sosyal Medya)"],
